final:
module RefModule(
	input 		en,
	input	[2-1:1-1] binary_in,

	output reg [3:0] dec_out
);

always @(*) begin
	if(!en)
		dec_out = 4'b0000;
	else begin
		case(binary_in)
			2'b00: dec_out = 4'b0001;
			2'b01: dec_out = 4'b0010;
			2'b10: dec_out = 4'b0100;
			2'b11: dec_out = 4'b1000;
			default: dec_out = 4'b0000;
		endcase
	end
end

endmodule
